const fs = require('fs');
let ctx = {};
try { ctx = JSON.parse(fs.readFileSync('/data/KAI_Context.json', 'utf8')); } catch(e) { ctx = {}; }
const entities = ctx.entities || {};
const founder = ctx.founder || {};
const tech = ctx.technology || {};
const revenue = ctx.revenue_targets || {};
const activeDeadlines = (ctx.deadlines || []).filter(function(d) {
  const st = (d.status || '').toUpperCase();
  return st !== 'FILED' && st !== 'COMPLETE' && st !== 'EXEMPT';
});
const eafProfile = 'ORGANIZATION: ' + (entities.EAF && entities.EAF.name ? entities.EAF.name : 'KAI-Netics Equity & Autonomy Foundry') + '\nEIN: ' + (entities.EAF && entities.EAF.ein ? entities.EAF.ein : '41-4820296') + '\nTYPE: ' + (entities.EAF && entities.EAF.type ? entities.EAF.type : 'Maryland Nonstock Corp 501c3 pending') + '\nSTATUS: ' + (entities.EAF && entities.EAF.status ? entities.EAF.status : '') + '\nROLE: ' + (entities.EAF && entities.EAF.role ? entities.EAF.role : '') + '\nFOUNDER: ' + (founder.name || '') + ' -- ' + (founder.credentials || []).join(', ') + '\nPROGRAMS: CAKO | MONK | Talent Pipeline Agreement' + '\nSERVICE AREA: Maryland, DC Metro, Northern Virginia' + '\nREVENUE IMPACT: Y1 ' + (revenue.year1_total || '') + ' Y2 ' + (revenue.year2_total || '') + ' Y3 ' + (revenue.year3_total || '') + '\nACTIVE DEADLINES: ' + activeDeadlines.map(function(d) { return d.item + ' | ' + d.date; }).join(' | ') + '\nCOMPLIANCE: NO funds flow FP to EAF. Talent Pipeline Agreement is only structural link.';
const dirPath = '/data/Maryland_Grants/';
let grantFiles = [];
try { grantFiles = fs.readdirSync(dirPath).filter(function(f) { return f.endsWith('.txt') || f.endsWith('.md'); }); } catch(e) { grantFiles = []; }
if (grantFiles.length === 0) {
  return [{ json: { fileName: 'No grant files', content: 'No files in /data/Maryland_Grants/', eafProfile: eafProfile, noFiles: true } }];
}
return grantFiles.map(function(file) {
  let content = '';
  try { content = fs.readFileSync(dirPath + file, 'utf8'); } catch(e) { content = 'Could not read: ' + e.message; }
  return { json: { fileName: file, content: content, eafProfile: eafProfile, noFiles: false } };
});

const input = $input.first().json;
const fileName = input.fileName;
const content = input.content;
const eafProfile = input.eafProfile;
const systemMessage = 'You are Jordan, Grant Writer for KAI-Netics EAF. Expert in Maryland workforce development grants, federal SBIR, nonprofit funding. Analyze grants and draft winning applications. Concise, professional, outcome-focused.';
const userMessage = 'GRANT: ' + fileName + '
CONTENT:
' + content + '
EAF PROFILE:
' + eafProfile + '

Analyze:
1. FUNDER
2. DEADLINE
3. AWARD RANGE
4. ELIGIBILITY (flag risks)
5. FIT SCORE 0-100% with rationale
6. TOP 3 ALIGNMENT POINTS
7. TOP 2 RISKS
8. RECOMMENDED ACTION: Apply/Pass/Watch

If fit 60%+, also draft:
9. LETTER OF INTENT (250-350 words)';
return [{ json: { systemMessage: systemMessage, userMessage: userMessage, fileName: fileName } }];

const https = require('https');
const input = $input.first().json;
const systemMessage = input.systemMessage;
const userMessage = input.userMessage;
const fileName = input.fileName;
const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 4096,
  system: systemMessage,
  messages: [{ role: 'user', content: userMessage }]
});
const options = {
  hostname: 'api.anthropic.com',
  port: 443,
  path: '/v1/messages',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'x-api-key': 'REPLACE_WITH_ANTHROPIC_KEY',
    'anthropic-version': '2023-06-01',
    'Content-Length': Buffer.byteLength(requestBody)
  }
};
const result = await new Promise(function(resolve, reject) {
  const req = https.request(options, function(res) {
    let d = '';
    res.on('data', function(c) { d += c; });
    res.on('end', function() { resolve({ status: res.statusCode, body: d }); });
  });
  req.on('error', reject);
  req.write(requestBody);
  req.end();
});
let aiOutput = '';
try { aiOutput = JSON.parse(result.body).content[0].text || 'No response.'; } catch(e) { aiOutput = result.body.substring(0, 500); }
return [{ json: { aiOutput: aiOutput, fileName: fileName, status: result.status } }];

const fs = require('fs');
const crypto = require('crypto');
const input = $input.first().json;
const aiOutput = input.aiOutput;
const fileName = input.fileName;
const timestamp = new Date().toISOString();

let safeName = '';
for (let i = 0; i < fileName.length; i++) {
  const code = fileName.charCodeAt(i);
  if ((code >= 65 && code <= 90) || (code >= 97 && code <= 122) || (code >= 48 && code <= 57)) {
    safeName = safeName + fileName[i];
  } else {
    safeName = safeName + '_';
  }
}

const safeTime = timestamp.split(':').join('-').split('.').join('-');
const outputPath = '/data/Aidan_Outputs/Jordan/Grant_Report_' + safeTime + '_' + safeName + '.txt';
fs.mkdirSync('/data/Aidan_Outputs/Jordan', { recursive: true });
fs.writeFileSync(outputPath, 'JORDAN GRANT REPORT v3 -- EAF\nFile: ' + fileName + '\nGenerated: ' + timestamp + '\n\n' + aiOutput, 'utf8');

let fitScore = null;
const fitLines = aiOutput.split('\n');
for (let i = 0; i < fitLines.length; i++) {
  const line = fitLines[i];
  if (line.toUpperCase().indexOf('FIT SCORE') !== -1) {
    const nums = line.match(/\d+/);
    if (nums) { fitScore = parseInt(nums[0]); break; }
  }
}
const fitScoreDisplay = fitScore !== null ? fitScore + '%' : 'See report';

let funder = 'See report';
for (let i = 0; i < fitLines.length; i++) {
  const line = fitLines[i];
  if (line.toUpperCase().indexOf('FUNDER') !== -1 && line.indexOf(':') !== -1) {
    funder = line.split(':').slice(1).join(':').trim().replace(/\*/g, '').substring(0, 60);
    break;
  }
}

let action = 'Review report';
for (let i = 0; i < fitLines.length; i++) {
  const line = fitLines[i];
  if (line.toUpperCase().indexOf('RECOMMENDED ACTION') !== -1 && line.indexOf(':') !== -1) {
    action = line.split(':').slice(1).join(':').trim().replace(/\*/g, '');
    break;
  }
}

let deadline = null;
for (let i = 0; i < fitLines.length; i++) {
  const line = fitLines[i];
  if (line.toUpperCase().indexOf('DEADLINE') !== -1 && line.indexOf(':') !== -1) {
    deadline = line.split(':').slice(1).join(':').trim().replace(/\*/g, '').substring(0, 50);
    break;
  }
}

const loiDrafted = aiOutput.toLowerCase().indexOf('letter of intent') !== -1;
const summary = 'JORDAN GRANT ANALYSIS COMPLETE\nFile: ' + fileName + '\nFunder: ' + funder + '\nFit: ' + fitScoreDisplay + '\nAction: ' + action + '\\nSaved: ' + outputPath;
const contentHash = crypto.createHash('md5').update(fileName + new Date().toISOString().slice(0, 10)).digest('hex');

return [{ json: {
  summary: summary,
  outputPath: outputPath,
  fileName: fileName,
  fitScore: fitScore,
  fitScoreDisplay: fitScoreDisplay,
  funder: funder,
  action: action,
  deadline: deadline,
  loiDrafted: loiDrafted,
  aiOutput: aiOutput,
  timestamp: timestamp,
  contentHash: contentHash
} }];

const https = require('https');
const input = $input.first().json;
const SUPABASE_URL = 'raxpmeltyxmtiihxoxpa.supabase.co';
const SUPABASE_KEY = process.env.SUPABASE_KEY;
let actionCode = null;
if (input.action) {
  const a = input.action.toUpperCase();
  if (a.indexOf('APPLY') !== -1) { actionCode = 'APPLY'; }
  else if (a.indexOf('PASS') !== -1) { actionCode = 'PASS'; }
  else if (a.indexOf('WATCH') !== -1) { actionCode = 'WATCH'; }
}
const record = {
  grant_file: input.fileName,
  funder: input.funder !== 'See report' ? input.funder : null,
  fit_score: input.fitScore || null,
  recommended_action: actionCode,
  loi_drafted: input.loiDrafted || false,
  jordan_report_path: input.outputPath,
  application_status: 'analyzing',
  entity: 'EAF'
};
try {
  const body = JSON.stringify(record);
  const result = await new Promise(function(resolve, reject) {
    const req = https.request({
      hostname: SUPABASE_URL,
      port: 443,
      path: '/rest/v1/grant_applications',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Prefer': 'resolution=merge-duplicates', 'on_conflict': 'grant_file',
        'Content-Length': Buffer.byteLength(body)
      }
    }, function(res) {
      let d = '';
      res.on('data', function(c) { d += c; });
      res.on('end', function() { resolve({ status: res.statusCode, body: d }); });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
  const logged = result.status === 201 || result.status === 200;
  const out = {};
  const keys = Object.keys(input);
  for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
  out.supabaseLogged = logged;
  out.supabaseStatus = result.status;
  return [{ json: out }];
} catch(e) {
  const out = {};
  const keys = Object.keys(input);
  for (let i = 0; i < keys.length; i++) { out[keys[i]] = input[keys[i]]; }
  out.supabaseLogged = false;
  out.supabaseError = e.message;
  return [{ json: out }];
}

